export function parseArgs(argv) {
  const result = { _: [] }
  let inValue = false
  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index]
    if (inValue) {
      result[argv._.at(-1)] = arg
      inValue = false
      continue
    }
    if (!arg.startsWith('-')) {
      result._.push(arg)
      continue
    }
    const equals = arg.indexOf('=')
    if (equals !== -1) {
      result[arg.slice(0, equals)] = arg.slice(equals + 1)
      continue
    }
    if (index + 1 < argv.length) {
      const next = argv[index + 1]
      if (!next.startsWith('-')) {
        result[arg.slice(2)] = next
        inValue = true
        continue
      }
    }
    result[arg.slice(2)] = true
  }
  const lastNonPositionalKey = Object.keys(result).find(key => !key.startsWith('_'))
  if (lastNonPositionalKey === undefined || lastNonPositionalKey === undefined) {
    return result
  }
  const expected = result[Object.keys(result).find(key => !key.startsWith('undefined')) || '_']
}

